{
  "name": "Wisconsin Home Energy Assistance Program (WHEAP)",
  "eligibility": {
    "age": null,
    "income_limits": "Gross monthly household income must be below limits (varies by program year; recent examples: 1-person: $3,389.42 monthly ($40,673 annually), 2: $4,186.92 ($50,243), 3: $4,984.42 ($59,813), 4: $5,781.92 ($69,383), 5: $6,579.42 ($78,953), 6: $6,729 ($80,748), 7: $6,878.50 ($82,542), 8: varies. Uses previous month's income; self-employed/farmers use prior year tax forms. Older guidelines (2020-21) showed higher annuals like 1-person $66,658.[1][3]",
    "asset_limits": "No asset limits mentioned in sources.",
    "other_requirements": ["U.S. citizenship or lawful immigration status.", "Social Security Number and date of birth for all household members.", "Evidence of heating/electric costs for last 12 months.", "Household responsible for primary heating costs (most fuel types eligible: wood, propane, natural gas, electricity, fuel oil)."]
  },
  "benefits": {
    "type": "financial",
    "value": "One-time payment during heating season (Oct 1-May 15) covering portion of heating costs, non-heating electric costs, or energy crisis. Amount varies by household size, income, and energy costs; not full coverage. Additional: HE+ HVAC repairs/replacements for inoperable systems, HE+ Water Conservation for leaky fixtures/water heaters/toilets/piping (year-round), Weatherization referral for energy efficiency upgrades at no cost.[1][6]",
    "varies_by": "household_size|income|energy_costs|priority_tier"
  },
  "application": {
    "methods": ["Online: https://energybenefit.wi.gov/", "Phone: Statewide Customer Care Center 1-800-506-5596 or 1-866-HEATWIS (432-8947); local agencies e.g., Douglas County (715) 395-1651, Partners for Community Development (833) 646-0823.", "In-person/mail: Local WHEAP agency (e.g., Partners for Community Development, 1407 S. 13th Street, Sheboygan, WI 53081)."],
    "processing_time": "Up to 10 business days for online review; incomplete apps denied after 30 days. May contact for more info.[6]",
    "waitlist": "Not mentioned; high application volume noted.",
    "forms": ["Home Energy Plus application (covers WHEAP, Weatherization, HE+ services)."],
    "documents": ["SSN and DOB for all household members.", "Proof of citizenship/immigration status.", "Heating/electric bills (account number, last 12 months).", "If renting: landlord name/address/phone or lease.", "Gross income proof for prior month (pay stubs, tax docs, award letters for wages, SS/SSI/SSDI, pensions, veterans, child support, TANF/W2, etc.)."]
  },
  "geography": {
    "statewide": true,
    "restrictions": "None; available across Wisconsin.",
    "regional_variations": "Administered by local WHEAP agencies with varying contact info/providers (e.g., Douglas County, Partners for Community Development in Sheboygan area); may have regional wait times or processes but no specific differences detailed.",
    "offices_or_providers": ["Local WHEAP agencies; find via https://energybenefit.wi.gov/ or Customer Care Center."]
  },
  "official_source": "https://energybenefit.wi.gov/",
  "gotchas": ["One-time benefit per heating season only (Oct 1-May 15).", "Payment covers portion, not full costs.", "Must apply through local agency or online; incomplete apps denied after 30 days.", "For crisis/disconnection, call immediately.", "Income based on prior month (or prior year taxes for self-employed); provide 12-month energy history.", "Weatherization/HE+ services referred separately if eligible.", "Program year-specific income limits; check current via official site."],
  "data_shape_notes": "Income limits provided as monthly/annual by household size with examples from different years; benefits as one-time variable payments plus referrals to weatherization/HVAC/water services; local agency administration statewide."
}
